1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life - Next Generation", () => {
6	  it("should return an empty grid when given an empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell with 0 neighbors (underpopulation)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
13	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
14	  });
15	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
16	    const sortCells = (cells: [number, number][]) =>
17	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
18	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
19	    expect(sortCells(result)).toEqual(sortCells([[0, 0], [1, 0], [0, 1], [1, 1]]));
20	  });
21	  it("should keep a block still life unchanged (each cell has 3 neighbors, survives)", () => {
22	    const sortCells = (cells: [number, number][]) =>
23	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
24	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
25	    expect(sortCells(result)).toEqual(sortCells([[0, 0], [1, 0], [0, 1], [1, 1]]));
26	  });
27	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
28	    const sortCells = (cells: [number, number][]) =>
29	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
30	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
31	    expect(sortCells(result)).toEqual(sortCells([[-1, 1], [0, 1], [1, 1]]));
32	  });
33	  it.todo("should kill the center of a full 3x3 block due to overpopulation while corners survive");
34	  it.todo("should handle negative coordinates correctly");
35	});
36

1	export type Cell = [number, number];
2	
3	const encodeCell = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const neighbors: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      neighbors.push([x + dx, y + dy]);
11	    }
12	  }
13	  return neighbors;
14	};
15	
16	const survives = (isAlive: boolean, liveNeighborCount: number): boolean =>
17	  (isAlive && (liveNeighborCount === 2 || liveNeighborCount === 3)) ||
18	  (!isAlive && liveNeighborCount === 3);
19	
20	export function nextGeneration(liveCells: Cell[]): Cell[] {
21	  const liveSet = new Set(liveCells.map(encodeCell));
22	  const candidatesByKey = new Map<string, Cell>();
23	  for (const cell of liveCells) {
24	    candidatesByKey.set(encodeCell(cell), cell);
25	    for (const neighbor of neighborsOf(cell)) {
26	      candidatesByKey.set(encodeCell(neighbor), neighbor);
27	    }
28	  }
29	  const result: Cell[] = [];
30	  for (const [key, cell] of candidatesByKey) {
31	    const liveNeighborCount = neighborsOf(cell).filter((n) =>
32	      liveSet.has(encodeCell(n))
33	    ).length;
34	    if (survives(liveSet.has(key), liveNeighborCount)) {
35	      result.push(cell);
36	    }
37	  }
38	  return result;
39	}
